.verify-btn { font-size: calc(0.85em * var(--font-scale)); padding: 5px 14px; border: 1px solid rgba(var(--c-prim), 0.5); border-radius: 6px; color: rgb(var(--c-prim)); cursor: pointer; background: rgba(var(--c-prim), 0.1); transition: var(--tr); display: flex; align-items: center; gap: 6px; }
