.beneath-dot.active.lv3 { background: rgb(var(--c-sec)); box-shadow: 0 0 8px rgb(var(--c-sec)), 0 0 16px rgb(var(--c-sec)); animation: beneathPulse 1.5s ease-in-out infinite; }
