.file-imp-tag.negative { background: linear-gradient(135deg, rgba(220, 60, 60, 0.2), rgba(255, 100, 100, 0.15)); border: 1px solid rgba(220, 60, 60, 0.5); color: rgb(var(--c-neg)); }
.file-imp-tag.neutral { background: rgba(var(--c-prim), 0.12); border: 1px solid rgba(var(--c-prim), 0.4); color: rgb(var(--c-prim)); }

.file-state-bar { display: flex; gap: 12px; flex-wrap: wrap; padding: 10px 14px; background: rgba(var(--c-bg), 0.5); border-radius: 8px; border: 1px solid rgba(var(--c-border), 0.3); }
