.settings-btn { display: flex; align-items: center; justify-content: center; gap: 10px; padding: 14px 30px; cursor: pointer; background: rgba(var(--c-surf), 0.9); border: 1px solid rgba(var(--c-prim), 0.4); border-radius: 10px; color: rgb(var(--c-prim)); transition: var(--tr); font-family: var(--f-code); font-weight: 600; font-size: calc(1em * var(--font-scale)); margin: 16px auto; }
.settings-btn:hover { background: rgba(var(--c-prim), 0.2); border-color: rgb(var(--c-prim)); transform: translateY(-3px); box-shadow: 0 8px 24px rgba(var(--c-prim), 0.2); }

.raw-data-toggle { text-align: center; font-size: calc(0.95em * var(--font-scale)); opacity: 0.6; cursor: pointer; padding: 14px; border: 1px dashed rgba(var(--c-text), 0.2); border-radius: 8px; font-family: var(--f-code); background: rgba(var(--c-bg), 0.3); transition: var(--tr); }
.raw-data-toggle:hover { opacity: 1; color: rgb(var(--c-prim)); border-color: rgb(var(--c-prim)); background: rgba(var(--c-prim), 0.1); }
.raw-data-box { display: none; margin-top: 14px; padding: 18px; background: rgba(0,0,0,0.4); border-radius: 8px; font-family: var(--f-code); font-size: calc(0.9em * var(--font-scale)); white-space: pre-wrap; overflow-x: auto; max-height: 450px; color: rgb(var(--c-text)); line-height: 1.9; }
.raw-data-box.show { display: block; }

@keyframes slideDown { from { opacity: 0; transform: translateY(-10px); } to { opacity: 1; transform: translateY(0); } }

.settings-modal { position: fixed; inset: 0; background: rgba(0,0,0,0.85); z-index: 999999; display: none; align-items: center; justify-content: center; backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px); }
.settings-modal.on { display: flex; }
.set-win { width: 90%; max-width: 550px; background: rgb(var(--c-surf)); border: 1px solid rgb(var(--c-border)); border-radius: var(--r-card); padding: 24px; max-height: 85vh; overflow-y: auto; }
.set-title { font-family: var(--f-head); font-size: calc(1.2em * var(--font-scale)); font-weight: bold; margin-bottom: 20px; border-bottom: 1px solid rgba(var(--c-border),0.5); padding-bottom: 14px; display: flex; justify-content: space-between; align-items: center; color: rgb(var(--c-text)); }
