.set-row select { padding: 6px 12px; border-radius: 6px; background: rgba(var(--c-bg), 0.5); border: 1px solid rgba(var(--c-border), 0.5); color: rgb(var(--c-text)); font-size: calc(0.95em * var(--font-scale)); }

.set-btn { width: 100%; padding: 12px; background: rgb(var(--c-prim)); color: #000; font-weight: bold; border: none; cursor: pointer; margin-top: 8px; border-radius: var(--r-card); font-size: calc(1em * var(--font-scale)); }

@media (max-width: 1000px) { .npc-grid { grid-template-columns: 1fr; } .mem-grid { grid-template-columns: repeat(4, 1fr); } .npc-chips { grid-template-columns: repeat(4, 1fr); } .stats-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 700px) { body { font-size: calc(12px * var(--font-scale)) !important; } .mem-grid { grid-template-columns: repeat(3, 1fr); } .npc-chips { grid-template-columns: repeat(3, 1fr); } .swipe-tab span { display: none; } }
</style>
