    const emotionToEmoji = (emo) => { if (!emo) return '😐'; const e = emo.toLowerCase(); if (/开心|高兴|愉快|快乐|喜悦|满足/.test(e)) return '😊'; if (/期待|兴奋|激动/.test(e)) return '🤩'; if (/宠溺|温柔|疼爱|柔情/.test(e)) return '🥰'; if (/撒娇|依赖|黏人/.test(e)) return '🥺'; if (/得意|自豪|骄傲|掌控|狡黠/.test(e)) return '😏'; if (/从容|游刃有余|自信/.test(e)) return '😎'; if (/平静|冷静|淡定/.test(e)) return '😌'; if (/调皮|俏皮|促狭/.test(e)) return '😜'; if (/感动|动容|触动/.test(e)) return '🥹'; if (/暧昧|心动|悸动/.test(e)) return '😳'; if (/好奇|探究|审视/.test(e)) return '🧐'; if (/思索|沉思|若有所思/.test(e)) return '🤔'; if (/无奈|哭笑不得|苦笑/.test(e)) return '😅'; if (/尴尬|窘迫/.test(e)) return '🫣'; if (/愤怒|生气|恼火/.test(e)) return '😠'; if (/悲伤|难过|伤心/.test(e)) return '😢'; if (/紧张|焦虑|不安/.test(e)) return '😰'; if (/害怕|恐惧/.test(e)) return '😨'; if (/惊讶|震惊/.test(e)) return '😮'; if (/困惑|迷惑/.test(e)) return '🤔'; if (/厌恶|嫌弃/.test(e)) return '😒'; if (/疲惫|累/.test(e)) return '😩'; if (/害羞|羞涩/.test(e)) return '😳'; if (/冷漠|冷淡/.test(e)) return '😐'; return '😐'; };
    const relationToPercent = rel => { if (!rel) return 20; const r = rel.toLowerCase(); if (/热恋|挚爱|深爱/.test(r)) return 95; if (/恋人|情侣/.test(r)) return 80; if (/暧昧|心动|好感/.test(r)) return 65; if (/好友|挚友/.test(r)) return 55; if (/朋友/.test(r)) return 45; if (/熟人/.test(r)) return 30; if (/陌生/.test(r)) return 15; return 40; };
