    const extractLocationName = (loc) => { if (!loc) return ''; let name = loc.split(/[—–\-]/)[0].trim(); name = name.replace(/[（(][^）)]*[）)]/g, '').trim(); if (name.length > 20) name = name.substring(0, 20) + '...'; return name; };
