    const DB = { init: () => new Promise(res => { const r = indexedDB.open('BaizeData_V10', 1); r.onupgradeneeded = e => { if(!e.target.result.objectStoreNames.contains('photos')) e.target.result.createObjectStore('photos', {keyPath: 'name'}); }; r.onsuccess = e => res(e.target.result); }), savePhoto: (n, b) => DB.init().then(db => { db.transaction('photos', 'readwrite').objectStore('photos').put({name: n, blob: b}); }), getPhoto: (n) => DB.init().then(db => new Promise(res => { const req = db.transaction('photos', 'readonly').objectStore('photos').get(n); req.onsuccess = () => res(req.result ? req.result.blob : null); })), clear: () => DB.init().then(db => { db.transaction('photos', 'readwrite').objectStore('photos').clear(); }) };

    const Fetcher = { _cachedContext: null, _forceRefresh: false, _lastSwipeId: null, _isolatedFloors: new Set(), getContext() { if (this._forceRefresh) { this._cachedContext = null; this._forceRefresh = false; } if (this._cachedContext) return this._cachedContext; try { if (window.parent?.SillyTavern?.getContext) { this._cachedContext = window.parent.SillyTavern.getContext(); return this._cachedContext; } if (typeof window.parent?.getContext === 'function') { this._cachedContext = window.parent.getContext(); return this._cachedContext; } } catch(e) {} try { if (window.SillyTavern?.getContext) { this._cachedContext = window.SillyTavern.getContext(); return this._cachedContext; } if (typeof getContext === 'function') { this._cachedContext = getContext(); return this._cachedContext; } } catch(e) {} return null; }, forceRefresh() { this._forceRefresh = true; this._cachedContext = null; }, getChat() { const ctx = this.getContext(); return ctx?.chat ? [...ctx.chat] : []; }, getChatLength() { return this.getChat().length; }, getCurrentFloor() { const chat = this.getChat(); for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user) return i; } return chat.length - 1; }, getCurrentSwipeId() { const chat = this.getChat(); if (!chat.length) return null; const last = chat[chat.length - 1]; if (!last) return null; return `${chat.length}-${last.swipe_id || 0}-${(last.mes || '').length}`; }, findMsgIndex(txt) { const chat = this.getChat(); if (!chat.length || !txt) return -1; const lines = txt.split('\n'); let feature = ''; for (const l of lines) { const t = l.trim(); if (t.length >= 2) { feature = t; break; } } if (!feature) feature = txt.replace(/[\n\r\s]+/g, ' ').trim().slice(0, 50); if (!feature || feature.length < 2) return -1; for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user && (chat[i].mes || '').includes(feature)) return i; } return -1; }, getQrfFromIndex(idx) { const chat = this.getChat(); if (idx < 0 || idx >= chat.length) return ''; return chat[idx].extra?.qrf_plot || chat[idx].qrf_plot || ''; }, getFromIndex(idx, tag) { const qrf = this.getQrfFromIndex(idx); const m = qrf.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i')); return m ? m[1].trim() : ''; }, getLatestFile() { const chat = this.getChat(); const regex = /<file[^>]*>([\s\S]*?)<\/file>/i; const currentFloor = this.getCurrentFloor(); for (let i = chat.length - 1; i >= 0; i--) { const msg = chat[i]; if (!msg) continue; const sources = [msg.extra?.qrf_plot, msg.qrf_plot]; if (msg.swipes && Array.isArray(msg.swipes)) { for (const swipe of msg.swipes) { if (swipe?.extra?.qrf_plot) sources.push(swipe.extra.qrf_plot); } } for (const src of sources.filter(Boolean)) { const match = src.match(regex); if (match && match[1] && match[1].length > 50) return { idx: i, content: match[1].trim(), isCurrentFloor: i >= currentFloor - 1 }; } } return { idx: -1, content: '', isCurrentFloor: false }; }, markFloorIsolated(idx) { this._isolatedFloors.add(idx); }, clearIsolation() { this._isolatedFloors.clear(); }, getReviewsFromIndex(idx) { const qrf = this.getQrfFromIndex(idx); const results = []; const regex = /<review\s+npc=['"]([^'"]+)['"][^>]*>([\s\S]*?)<\/review>/gi; let m; while ((m = regex.exec(qrf)) !== null) results.push({ npc: m[1], content: m[2].trim() }); return results; }, getRecentReviews(count = 10) { const chat = this.getChat(); const results = []; const regex = /<review\s+npc=['"]([^'"]+)['"][^>]*>([\s\S]*?)<\/review>/gi; for (let i = chat.length - 1; i >= Math.max(0, chat.length - count); i--) { const msg = chat[i]; const sources = [msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { if (!results.find(r => r.npc === m[1])) results.push({ npc: m[1], content: m[2].trim() }); } regex.lastIndex = 0; } if (results.length > 0) break; } return results; }, getUserInput() { const chat = this.getChat(); for (let i = chat.length - 1; i >= 0; i--) { if (chat[i].is_user) return chat[i].mes || ''; } return ''; }, extractTag(tag, opts = {}) { const { count = 10, all = false } = opts; const chat = this.getChat(); if (!chat.length) return all ? [] : ''; const regex = new RegExp(`<${tag}(?:\\s[^>]*)?>[\\s\\S]*?<\\/${tag}>`, 'gi'); const results = []; const limit = Math.max(0, chat.length - count); for (let i = chat.length - 1; i >= limit; i--) { const msg = chat[i]; const sources = [msg.mes, msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { const inner = m[0].replace(new RegExp(`^<${tag}[^>]*>|<\\/${tag}>$`, 'gi'), '').trim(); results.push({ content: inner, fullMatch: m[0], msgIndex: i }); if (!all) return inner; } regex.lastIndex = 0; } } return all ? results : ''; }, countNpcAppearances() { const chat = this.getChat(); const counts = {}; const regex = /<!--(?:登场)?NPC=['"]([^'"]+)['"]/gi; for (const msg of chat) { const sources = [msg.mes, msg.extra?.qrf_plot, msg.qrf_plot].filter(Boolean); for (const src of sources) { let m; while ((m = regex.exec(src)) !== null) { const name = m[1].trim(); if (!isUserName(name)) counts[name] = (counts[name] || 0) + 1; } regex.lastIndex = 0; } } return counts; } };

    async function getAllEntries() { try { if (typeof getVariables === 'function') { const vars = await getVariables({ type: 'chat' }); let wb = vars?.selectedWorldBook; if (!wb && typeof getCurrentCharPrimaryLorebook === 'function') wb = await getCurrentCharPrimaryLorebook(); if (wb && typeof getLorebookEntries === 'function') return await getLorebookEntries(wb); } } catch(e) {} return []; }
    async function queryACDB(amId) { try { const api = window.AutoCardUpdaterAPI || window.parent?.AutoCardUpdaterAPI; if (api?.exportTableAsJson) { const db = api.exportTableAsJson(); const lower = amId.toLowerCase(); for (const id in db) { const sheet = db[id]; if (!sheet.content) continue; const row = sheet.content.find((r, i) => i > 0 && r.some(c => String(c).toLowerCase() === lower)); if (row) return { found: true, source: sheet.name, headers: sheet.content[0], data: row }; } } } catch(e) {} return { found: false }; }

    const App = {
        d: { theme: 'sakura-day', font: 'medium', width: 'wide', folded: false, stageFolds: { scene: false, objectives: false, dynamics: true, stagnation: true }, favs: [], tab: 'on', extremeCheck: true, extremeWords: null, customReplacements: {}, ignoredWords: [], processedWords: [], customExtremeWords: {}, removedBuiltinWords: [] },
        npcs: { on: [], off: [] }, memData: { recallIds: [], entries: [] }, npcMemoryMap: {}, reviewData: [],
