        sceneInfo: {}, stageData: {}, floorInfo: { idx: -1, fileLen: 0, reviewCount: 0, sceneLen: 0, usedFallback: false },
        rawFile: '', rawReview: '', rawScene: '', currentPage: 0, npcAppearances: {},
        extremeWordsFound: [], extremeContexts: [], processedText: '',
        _swipeWatcher: null, _lastDataHash: '', _lastContentLength: 0, _stableCheckTimer: null, _hasFetchedOnce: false, _previousFloor: -1,
        _uiState: { openNpcCards: [], openNpcReviews: [] },

        getExtremeWords() { return this.d.extremeWords !== null ? this.d.extremeWords : [...DEFAULT_EXTREME_WORDS]; },
        getActiveExtremeWords() { const ignored = this.d.ignoredWords || []; const processed = this.d.processedWords || []; return this.getExtremeWords().filter(w => !ignored.includes(w) && !processed.includes(w)); },
        getReplacements() { return { ...DEFAULT_REPLACEMENTS, ...(this.d.customReplacements || {}) }; },

        applyExtremeFilter(text) {
            if (!text || !this.d.extremeCheck) return text;
            const words = this.getExtremeWords();
            const ignored = this.d.ignoredWords || [];
            const replacements = this.getReplacements();
            let result = text;
            for (const word of words) {
                if (result.includes(word) && !ignored.includes(word)) {
                    const replacement = replacements[word] || '';
                    result = result.split(word).join(replacement);
                }
            }
            return result;
        },

        detectExtremeWords(text) {
            if (!text) return { found: [], contexts: [], cleaned: text };
            const words = this.getExtremeWords().filter(w => !(this.d.removedBuiltinWords || []).includes(w));
            const ignored = this.d.ignoredWords || [];
            const processed = this.d.processedWords || [];
            const replacements = this.getReplacements();
            const found = []; const contexts = []; let cleaned = text;
            for (const word of words) {
                if (text.includes(word)) {
                    found.push(word);
                    const idx = text.indexOf(word); const start = Math.max(0, idx - 15); const end = Math.min(text.length, idx + word.length + 15);
                    let context = text.slice(start, end); if (start > 0) context = '...' + context; if (end < text.length) context = context + '...';
                    contexts.push({ word, context, replacement: replacements[word] || '', isIgnored: ignored.includes(word), isProcessed: processed.includes(word) });
