                }
            }
            return { found: [...new Set(found)], contexts, cleaned };
        },

        init() {
            const s = localStorage.getItem('baize_v10_pc_cfg'); if (s) try { Object.assign(this.d, JSON.parse(s)); } catch(e) {}
            if (!this.d.processedWords) this.d.processedWords = [];
