        startSwipeWatcher() { if (this._swipeWatcher) clearInterval(this._swipeWatcher); Fetcher._lastSwipeId = Fetcher.getCurrentSwipeId(); this._lastContentLength = 0; this._hasFetchedOnce = false; this._swipeWatcher = setInterval(() => { const currentId = Fetcher.getCurrentSwipeId(); if (currentId && currentId !== Fetcher._lastSwipeId) { Fetcher._lastSwipeId = currentId; this.onSwipeChange(); } }, 800); },
        onSwipeChange() { if (this._stableCheckTimer) { clearInterval(this._stableCheckTimer); this._stableCheckTimer = null; } const currentFloor = Fetcher.getCurrentFloor(); if (currentFloor !== this._previousFloor) { Fetcher.clearIsolation(); this._previousFloor = currentFloor; this.d.processedWords = []; this.save(); } if (!this._hasFetchedOnce) { this._hasFetchedOnce = true; this.doQuietFetch(); } this.startStabilityCheck(); },
        startStabilityCheck() { let stableCount = 0; const chat = Fetcher.getChat(); const lastMsg = chat[chat.length - 1]; this._lastContentLength = lastMsg?.mes?.length || 0; this._stableCheckTimer = setInterval(() => { const chat = Fetcher.getChat(); const lastMsg = chat[chat.length - 1]; const currentLength = lastMsg?.mes?.length || 0; if (currentLength === this._lastContentLength) { stableCount++; if (stableCount >= 3) { clearInterval(this._stableCheckTimer); this._stableCheckTimer = null; this._hasFetchedOnce = false; this.doFinalFetch(); } } else { stableCount = 0; this._lastContentLength = currentLength; } }, 1000); },
