        verifyData() { const fe = this.memData.recallIds; const be = this.memData.entries.map(e => { const keys = e.keys || (e.key ? (Array.isArray(e.key) ? e.key : [e.key]) : []); return keys.filter(k => /^AM\d+$/i.test(k)); }).flat().map(k => k.toUpperCase()); const missing = fe.filter(id => !be.includes(id)); alert(missing.length > 0 ? `⚠️ 缺失条目: ${missing.join(', ')}` : `✅ 全部 ${fe.length} 条记忆已验证通过`); },

