            const list = this.d.tab === 'on' ? this.npcs.on : this.npcs.off; list.sort((a, b) => (b.f ? 1 : 0) - (a.f ? 1 : 0) || (b.isMain ? 1 : 0) - (a.isMain ? 1 : 0));
            const getReview = (name) => this.reviewData.find(r => r.npc === name);
            const isCardOpen = (name) => this._uiState.openNpcCards.includes(name);
            const isReviewOpen = (name) => this._uiState.openNpcReviews.includes(name);
            const parseReviewToBubbles = (content) => { const filtered = this.applyExtremeFilter(content); const blocks = filtered.split(/\[([^\]]+)\]/).filter(s => s.trim()); let bubbles = ''; let currentName = ''; for (const block of blocks) { const trimmed = block.trim(); if (trimmed.length <= 10 && !trimmed.includes('\n') && !trimmed.includes('。')) { currentName = trimmed; } else if (currentName) { const initial = currentName.charAt(0); const isEd = /爱德华|编辑|Ed/i.test(currentName); const cls = isEd ? 'ed' : 'al'; trimmed.split(/\n+/).filter(p => p.trim()).forEach(p => { bubbles += `<div class="review-row ${cls}"><div class="review-avatar ${cls}">${initial}</div><div class="review-bubble ${cls}"><span class="review-text">${p.trim()}</span></div></div>`; }); } } return bubbles; };
            const renderEmotionTrail = (trail) => { if (!trail || trail.length <= 1) return ''; return `<div class="emotion-trail">${trail.map((e, i) => { const emoji = emotionToEmoji(e); const arrow = i < trail.length - 1 ? '<i class="fa-solid fa-arrow-right emotion-arrow"></i>' : ''; return `<div class="emotion-node"><span class="emotion-emoji">${emoji}</span><span class="emotion-label">${e}</span></div>${arrow}`; }).join('')}</div>`; };
            const renderRelationBar = (rel) => { if (!rel) return ''; const pct = relationToPercent(rel); const stage = relationToStage(rel); return `<div class="relation-bar"><div class="relation-header"><span class="relation-label">关系进度</span><span class="relation-stage">${stage}</span></div><div class="relation-track"><div class="relation-fill" style="width:${pct}%"></div></div><div class="relation-markers"><span>陌生</span><span>熟人</span><span>朋友</span><span>恋人</span><span>挚爱</span></div></div>`; };
            const renderBeneathBar = (level) => { const dots = [0,1,2,3].map(i => { const active = i < level; const lv3 = level >= 3 && i < level; return `<div class="beneath-dot ${active ? 'active' : ''} ${lv3 ? 'lv3' : ''}"></div>`; }).join(''); return `<div class="beneath-dots">${dots}</div>`; };
            const renderSpeechBubble = (n) => { let speech = ''; if (n.initiative?.content) speech = n.initiative.content; else if (n.beat) speech = n.beat; else if (n.now) speech = n.now; if (!speech) return ''; return `<div class="speech-bubble"><div class="speech-bubble-text">${this.applyExtremeFilter(speech)}</div></div>`; };
            Promise.all(list.map(async (n, i) => {
                const isOff = n.isOff; const emoji = emotionToEmoji(n.emotion); const badge = isOff ? 'OFF' : (n.isMain ? 'MAIN' : 'SEC'); const review = getReview(n.n); const hasReview = !!review;
                let kvHtml = ''; const kv = (k, v) => v ? `<div class="kv"><span class="kv-k">${k}</span><span class="kv-v">${this.applyExtremeFilter(v)}</span></div>` : '';
                if (isOff) { kvHtml = kv('此刻', n.now) + kv('欲念', n.want_beneath) + kv('认知', n.cognitive) + kv('自主', n.autonomous_action) + kv('剧情', n.plot_relevance) + kv('登场', n.entry_prediction); }
                else { if (n.emotionTrail && n.emotionTrail.length > 1) kvHtml += renderEmotionTrail(n.emotionTrail); if (n.relation) kvHtml += renderRelationBar(n.relation); if (n.want) kvHtml += kv('欲念', `[${n.want.type}] ${n.want.content}`); if (n.beneath) kvHtml += `<div class="kv"><span class="kv-k">潜流</span><span class="kv-v"><div class="beneath-bar">${renderBeneathBar(n.beneath.level)}<span class="beneath-text">Lv${n.beneath.level} ${this.applyExtremeFilter(n.beneath.content)}</span></div></span></div>`; 
                if (n.own && n.own !== '—' && n.own !== '-') { kvHtml += `<div class="own-bubble"><div class="own-label"><i class="fa-solid fa-cloud"></i> 心声</div>${this.applyExtremeFilter(n.own)}</div>`; }
                kvHtml += kv('此刻', n.now) + kv('应对', n.beat) + kv('承启', n.handoff); 
