                let reviewHtml = ''; if (review) { const bubbles = parseReviewToBubbles(review.content); const reviewOpenClass = isReviewOpen(n.n) ? 'open' : ''; reviewHtml = `<div class="npc-review ${reviewOpenClass}" data-name="${n.n}"><div class="npc-review-header"><i class="fa-solid fa-comments"></i> 导演评论 <i class="fa-solid fa-chevron-down toggle"></i></div><div class="npc-review-body"><div class="review-chat-box">${bubbles}</div></div></div>`; }
