                return `<div class="npc-card ${n.f ? 'pinned' : ''} ${cardOpenClass}" data-name="${n.n}"><div class="npc-head" style="${imgUrl ? `background-image:url('${imgUrl}');background-size:cover;background-position:center` : ''}"><div class="npc-head-left" style="${imgUrl ? 'background:rgba(0,0,0,0.6);padding:6px 10px;border-radius:6px' : ''}"><span class="npc-emoji">${emoji}</span><span class="npc-name">${n.n}</span></div><div class="npc-badges"><span class="npc-badge ${isOff ? '' : (n.isMain ? 'main' : '')}">${badge}</span>${n.relation ? `<span class="npc-badge rel">${n.relation}</span>` : ''}${n.emotion ? `<span class="npc-badge emo">${n.emotion}</span>` : ''}${hasReview ? `<span class="npc-badge has-review"><i class="fa-solid fa-comment"></i></span>` : ''}</div><i class="fa-solid fa-chevron-down npc-chevron"></i></div><div class="npc-body"><div class="kv-box">${kvHtml || '<div style="opacity:0.5">无详细数据</div>'}</div>${reviewHtml}</div><div class="npc-actions"><div class="npc-act-btn ${n.f ? 'active' : ''}" data-action="fav" data-name="${n.n}"><i class="fa-solid fa-thumbtack"></i> ${n.f ? 'PINNED' : 'PIN'}</div><div class="npc-act-btn" data-action="photo" data-name="${n.n}"><i class="fa-solid fa-image"></i> PHOTO</div><input type="file" class="photo-uploader" data-name="${n.n}" style="display:none" accept="image/*"></div></div>`;
            })).then(cards => {
