        parseNPCArchives() { const txt = this.rawFile || ''; if (!txt || txt.length < 50) return []; const archives = []; const regex = /<!--NPC档案=['"]([^'"]+)['"][^>]*-->/gi; const matches = [...txt.matchAll(regex)]; for (let i = 0; i < matches.length; i++) { const m = matches[i]; const name = m[1].trim(); const fullMatch = m[0]; const startIdx = m.index + fullMatch.length; let endIdx = txt.length; if (i < matches.length - 1) endIdx = matches[i + 1].index; else { const endMarkers = [/<!--(?!NPC档案)/i, /<review\s/i, /<\/file>/i, /<timeskip/i]; for (const marker of endMarkers) { const endMatch = txt.slice(startIdx).match(marker); if (endMatch && startIdx + endMatch.index < endIdx) endIdx = startIdx + endMatch.index; } } const content = txt.slice(startIdx, endIdx).trim(); const statusM = fullMatch.match(/[（(]([IUM])[）)]/i); const status = statusM ? (statusM[1].toUpperCase() === 'I' ? '首次' : statusM[1].toUpperCase() === 'U' ? '更新' : '维持') : ''; const sections = {}; const sectionRegex = /【([^】]+)】\s*([\s\S]*?)(?=【|$)/g; let sm; while ((sm = sectionRegex.exec(content)) !== null) { const sectionName = sm[1].trim(); const sectionContent = sm[2].trim(); const fields = {}; sectionContent.split('\n').forEach(line => { line = line.trim(); if (!line) return; const kvMatch = line.match(/^([^:：]+)[：:]\s*(.+)$/); if (kvMatch) fields[kvMatch[1].trim()] = kvMatch[2].trim(); }); sections[sectionName] = Object.keys(fields).length > 0 ? fields : { _raw: sectionContent }; } const impTags = []; const impSection = sections['印象与状态'] || {}; const impRaw = impSection['印象'] || impSection._raw || ''; 
        if (impRaw) { const pipeIdx = impRaw.indexOf('|'); const impPart = pipeIdx > -1 ? impRaw.slice(0, pipeIdx) : impRaw; const restPart = pipeIdx > -1 ? impRaw.slice(pipeIdx + 1) : ''; const cleanSrc = t => t.replace(/[（(]来源[：:][^）)]*[）)]/g, '').trim(); const posM = impPart.match(/\+([^\-|｜]+)/); if (posM) { const t = cleanSrc(posM[1]); if (t) impTags.push({ text: '👍 ' + t, type: 'positive' }); } const negM = impPart.match(/-([^|｜]+)/); if (negM) { const t = cleanSrc(negM[1]); if (t) impTags.push({ text: '👎 ' + t, type: 'negative' }); } const expM = (restPart || impRaw).match(/预期[=＝]([^|｜\n]+)/i); if (expM) impTags.push({ text: '预期: ' + expM[1].trim(), type: 'neutral' }); } 
        const stateInfo = []; const stateRaw = impSection['状态'] || ''; if (stateRaw) stateRaw.split(/[|｜]/).forEach(s => { const kv = s.trim().match(/([^=＝]+)[=＝](.+)/); if (kv) stateInfo.push({ key: kv[1].trim(), val: kv[2].trim() }); }); const sensitive = impSection['敏感话题'] || ''; archives.push({ name, status, impTags, stateInfo, sensitive, sections }); } return archives; },

        renderSystem() {
