            const archives = this.parseNPCArchives();
            let archiveHtml = '';
            if (archives.length > 0) {
                archiveHtml = `<div class="sw-card"><div class="sw-card-header"><div class="title"><i class="fa-solid fa-address-book"></i> NPC档案</div><span class="badge">${archives.length}</span></div><div class="sw-card-body"><div class="file-archive">${archives.map((a, i) => {
                    const tagsHtml = a.impTags.length > 0 ? `<div class="file-imp-tags">${a.impTags.map(t => `<span class="file-imp-tag ${t.type}">${this.applyExtremeFilter(t.text)}</span>`).join('')}</div>` : '';
