                    const sensitiveHtml = a.sensitive ? `<div class="file-sensitive"><i class="fa-solid fa-triangle-exclamation"></i> ${this.applyExtremeFilter(a.sensitive)}</div>` : '';
                    let sectionsHtml = ''; for (const [sectionName, fields] of Object.entries(a.sections)) { if (sectionName === '印象与状态') continue; const fieldEntries = typeof fields === 'object' && !fields._raw ? Object.entries(fields) : []; if (fieldEntries.length > 0) sectionsHtml += `<div class="file-section"><div class="file-section-title"><i class="fa-solid fa-layer-group"></i> ${sectionName}</div><div class="file-fields">${fieldEntries.map(([k, v]) => `<div class="file-field"><div class="file-key">${k}</div><div class="file-val">${this.applyExtremeFilter(v)}</div></div>`).join('')}</div></div>`; else if (fields._raw) sectionsHtml += `<div class="file-section"><div class="file-section-title"><i class="fa-solid fa-layer-group"></i> ${sectionName}</div><div style="padding:10px;opacity:0.8">${this.applyExtremeFilter(fields._raw)}</div></div>`; }
                    return `<div class="file-item" data-idx="${i}"><div class="file-item-header"><div class="file-item-top"><div class="file-item-name"><i class="fa-solid fa-user-tag"></i> ${a.name} ${a.status ? `<span class="file-status-badge">${a.status}</span>` : ''}</div><i class="fa-solid fa-chevron-down file-item-chevron"></i></div>${tagsHtml}${stateHtml}${sensitiveHtml}</div><div class="file-item-body">${sectionsHtml || '<div style="opacity:0.5">无详细信息</div>'}</div></div>`;
                }).join('')}</div></div></div>`;
            }
            const fullRawData = `=== FILE (${this.rawFile.length}字) ===\n${this.rawFile || '无数据'}\n\n=== REVIEW (${this.reviewData.length}条) ===\n${this.rawReview || '无数据'}\n\n=== SCENE_DIRECTION (${this.rawScene.length}字) ===\n${this.rawScene || '无数据'}`;
            page.innerHTML = `<div class="sw-card"><div class="sw-card-header"><div class="title"><i class="fa-solid fa-palette"></i> 主题切换</div></div><div class="sw-card-body"><div class="theme-grid">${themes.map(t => `<div class="theme-dot" style="${t.id === 'ink' ? '' : `background:${t.color}`}" data-theme="${t.id}" title="${t.id}"></div>`).join('')}</div><div class="settings-btn" id="settings-btn"><i class="fa-solid fa-sliders"></i> 系统设置</div></div></div>${archiveHtml}<div class="sw-card"><div class="sw-card-header"><div class="title"><i class="fa-solid fa-code"></i> RAW DATA</div></div><div class="sw-card-body"><div class="raw-data-toggle" id="raw-toggle">[DEV] 点击展开原始数据 (不受禁词过滤影响)</div><div class="raw-data-box" id="raw-box">${fullRawData.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</div></div></div>`;
            page.querySelectorAll('.theme-dot').forEach(dot => { dot.addEventListener('click', () => this.setTheme(dot.dataset.theme)); });
            $('settings-btn')?.addEventListener('click', () => this.toggleSettings()); $('raw-toggle')?.addEventListener('click', () => $('raw-box').classList.toggle('show'));
            page.querySelectorAll('.file-item-header').forEach(hdr => { hdr.addEventListener('click', () => hdr.closest('.file-item').classList.toggle('open')); });
        },

        toggleFold() { this.d.folded = !this.d.folded; this.toggleFoldState(this.d.folded); },
        toggleFoldState(v) { if (v) $('app').classList.add('folded'); else $('app').classList.remove('folded'); this.d.folded = v; $('cfg-fold').checked = v; this.save(); },
        toggleFav(n) { if (this.d.favs.includes(n)) this.d.favs = this.d.favs.filter(x => x !== n); else this.d.favs.push(n); this.save(); this.renderNPC(); },
        setTheme(t) { this.d.theme = t; $('app').dataset.theme = t; $('cfg-theme').value = t; this.save(); },
        setFont(f) { this.d.font = f; $('app').dataset.font = f; $('cfg-font').value = f; this.save(); },
        setWidth(w) { this.d.width = w; $('app').dataset.width = w; $('cfg-width').value = w; this.save(); },
        toggleSettings() { $('settings').classList.toggle('on'); },
        uploadPhoto(n, file) { DB.savePhoto(n, file).then(() => this.renderNPC()); },
        reset() { if (confirm('重置所有设置和照片？')) { localStorage.removeItem('baize_v10_pc_cfg'); DB.clear(); location.reload(); } },
        save() { localStorage.setItem('baize_v10_pc_cfg', JSON.stringify(this.d)); }
    };

    window.App = App;
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', () => App.init()); else App.init();
})();
</script>
</body>
</html>
